import org.junit.Test
import kotlin.coroutines.*
import kotlin.test.*

class DispatcherFailureTest : TestBase() {
    @Test
    fun testLaunchDefaultDispatcherFailure() = runTest {
        val dispatcher = object : CoroutineDispatcher() {
            override fun dispatch(context: CoroutineContext, block: Runnable) {
                throw RuntimeException("Dispatch failed")
            }
        }

        try {
            launch(dispatcher) {
                println("Should not run")
            }
            fail("Should have thrown exception")
        } catch (e: RuntimeException) {
            assertEquals("Dispatch failed", e.message)
        }
    }

    @Test
    fun testLaunchUndispatchedDispatcherFailure() = runTest {
        val dispatcher = object : CoroutineDispatcher() {
            override fun isDispatchNeeded(context: CoroutineContext): Boolean = true
            override fun dispatch(context: CoroutineContext, block: Runnable) {
                throw RuntimeException("Dispatch failed")
            }
        }

